import { ApiChapterResponse, ApiVerseResponse } from '../types';

const BASE_URL = 'https://api.quran.com/api/v4';

export const fetchChapters = async (): Promise<ApiChapterResponse> => {
  const response = await fetch(`${BASE_URL}/chapters?language=en`);
  if (!response.ok) {
    throw new Error('Failed to fetch chapters');
  }
  return response.json();
};

export const fetchVerses = async (chapterId: number, page: number = 1): Promise<ApiVerseResponse> => {
  // translations=131 is generic clear Quran translation
  // fields=text_uthmani gets the arabic script
  const response = await fetch(
    `${BASE_URL}/verses/by_chapter/${chapterId}?language=en&words=false&translations=131&fields=text_uthmani&page=${page}&per_page=10`
  );
  if (!response.ok) {
    throw new Error('Failed to fetch verses');
  }
  return response.json();
};

// Getting audio is a bit separate in V4, often utilizing recitations endpoint
// For simplicity in this demo, we construct the audio URL if we were using the audio-specific endpoint, 
// but often standard usage involves checking recitations. 
// For this app, we will use a reliable CDN pattern for audio or skip complex audio mapping to keep it robust.
export const getAudioUrl = (verseKey: string): string => {
  // Format: 001001.mp3 (SurahPadVersePad)
  const [surah, verse] = verseKey.split(':');
  const padSurah = surah.padStart(3, '0');
  const padVerse = verse.padStart(3, '0');
  return `https://everyayah.com/data/Alafasy_128kbps/${padSurah}${padVerse}.mp3`;
};

