import React, { useState, useEffect } from 'react';
import { ArrowLeft, MoreHorizontal, Play, Pause, Share2, Bookmark } from 'lucide-react';
import { Chapter, Verse } from '../types';
import { fetchVerses, getAudioUrl } from '../services/quranService';
import { Loading } from './Loading';
import { QuickTools } from './QuickTools';

interface DetailViewProps {
  chapter: Chapter;
  onBack: () => void;
}

export const DetailView: React.FC<DetailViewProps> = ({ chapter, onBack }) => {
  const [verses, setVerses] = useState<Verse[]>([]);
  const [loading, setLoading] = useState(true);
  const [playingVerse, setPlayingVerse] = useState<string | null>(null);
  const [audio, setAudio] = useState<HTMLAudioElement | null>(null);
  const [showTools, setShowTools] = useState(false);
  const [showTranslation, setShowTranslation] = useState(true);
  const [fontSize, setFontSize] = useState(32);

  useEffect(() => {
    const loadVerses = async () => {
      try {
        const data = await fetchVerses(chapter.id);
        setVerses(data.verses);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadVerses();
    // Cleanup audio on unmount
    return () => {
      if (audio) {
        audio.pause();
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [chapter.id]);

  const toggleAudio = (verseKey: string) => {
    if (playingVerse === verseKey && audio) {
      audio.pause();
      setPlayingVerse(null);
      return;
    }

    if (audio) {
      audio.pause();
    }

    const url = getAudioUrl(verseKey);
    const newAudio = new Audio(url);

    newAudio.addEventListener('ended', () => {
      setPlayingVerse(null);
    });

    newAudio.play();
    setAudio(newAudio);
    setPlayingVerse(verseKey);
  };

  return (
    <div className="min-h-screen bg-[#FDF6F0] pb-24 animate-fade-in">
      {/* Header */}
      <div className="sticky top-0 bg-[#FDF6F0]/95 backdrop-blur-md z-30 px-4 py-4 border-b border-[#EDE0D4]">
        <div className="flex justify-between items-center">
          <button onClick={onBack} className="p-2 text-stone-600 hover:bg-stone-100 rounded-full transition-colors">
            <ArrowLeft size={24} />
          </button>
          <div className="text-center">
            <h2 className="font-bold text-stone-800 flex items-center gap-2 justify-center">
               <span>{chapter.id}. {chapter.name_simple}</span>
            </h2>
            <p className="text-xs text-stone-400">{chapter.translated_name.name}</p>
          </div>
          <button onClick={() => setShowTools(true)} className="p-2 text-stone-600 hover:bg-stone-100 rounded-full transition-colors">
            <MoreHorizontal size={24} />
          </button>
        </div>
      </div>

      {/* Surah Banner */}
      <div className="px-4 mt-6 mb-8">
        <div className="bg-gradient-to-br from-[#8B5E3C] to-[#6D4C41] rounded-2xl p-6 text-white text-center shadow-lg relative overflow-hidden">
             {/* Decorative Background Pattern Opacity */}
             <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none" 
                  style={{ backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)', backgroundSize: '20px 20px' }}>
             </div>

            <h1 className="font-arabic text-4xl mb-2">{chapter.name_arabic}</h1>
            <p className="text-white/80 text-sm mb-4">{chapter.name_simple} • {chapter.revelation_place}</p>
            <div className="w-full h-px bg-white/20 mb-4 mx-auto max-w-[200px]" />
            <div className="font-arabic text-2xl">بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</div>
        </div>
      </div>

      {loading ? (
        <Loading />
      ) : (
        <div className="px-4 space-y-6">
          {verses.map((verse) => (
            <div key={verse.id} className="bg-white rounded-2xl p-5 shadow-sm border border-[#EDE0D4] transition-all hover:shadow-md">
              {/* Action Bar */}
              <div className="flex justify-between items-center mb-6 bg-[#FAFAFA] rounded-lg p-2">
                <span className="w-8 h-8 flex items-center justify-center bg-[#8B5E3C] text-white text-xs font-bold rounded-full shadow-sm">
                  {verse.verse_key.split(':')[1]}
                </span>
                <div className="flex space-x-3 text-stone-400">
                  <button 
                    onClick={() => toggleAudio(verse.verse_key)}
                    className={`hover:text-[#8B5E3C] transition-colors ${playingVerse === verse.verse_key ? 'text-[#8B5E3C] animate-pulse' : ''}`}
                  >
                    {playingVerse === verse.verse_key ? <Pause size={18} /> : <Play size={18} />}
                  </button>
                  <button className="hover:text-[#8B5E3C] transition-colors"><Bookmark size={18} /></button>
                  <button className="hover:text-[#8B5E3C] transition-colors"><Share2 size={18} /></button>
                </div>
              </div>

              {/* Arabic Text */}
              <p 
                className="text-right font-arabic text-stone-800 leading-[2.5] mb-6"
                style={{ fontSize: `${fontSize}px` }}
              >
                {verse.text_uthmani}
              </p>

              {/* Translation */}
              {showTranslation && (
                <div className="text-stone-600 text-sm md:text-base leading-relaxed border-t border-stone-100 pt-4">
                  <p className="text-[10px] text-[#8B5E3C] uppercase tracking-wider font-bold mb-1">Sahih International</p>
                  {verse.translations?.[0]?.text.replace(/<[^>]*>/g, '')}
                </div>
              )}
            </div>
          ))}

          <div className="text-center py-6 text-stone-400 text-sm">
             End of loaded verses
          </div>
        </div>
      )}

      <QuickTools 
        isOpen={showTools} 
        onClose={() => setShowTools(false)} 
        showTranslation={showTranslation}
        toggleTranslation={() => setShowTranslation(!showTranslation)}
        fontSize={fontSize}
        setFontSize={setFontSize}
      />
    </div>
  );
};

