import React, { useState, useEffect } from 'react';
import { ArrowLeft, MoreHorizontal, Play, Pause, Share2, Bookmark, Search, X } from 'lucide-react';
import { Chapter, Verse } from '../types';
import { fetchVerses, getAudioUrl } from '../services/quranService';
import { Loading } from './Loading';
import { QuickTools } from './QuickTools';

interface DetailViewProps {
  chapter: Chapter;
  onBack: () => void;
}

export const DetailView: React.FC<DetailViewProps> = ({ chapter, onBack }) => {
  const [verses, setVerses] = useState<Verse[]>([]);
  const [loading, setLoading] = useState(true);

  // Audio State
  const [playingVerse, setPlayingVerse] = useState<string | null>(null);
  const [audio, setAudio] = useState<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioProgress, setAudioProgress] = useState(0);

  // Reading Progress State
  const [readingProgress, setReadingProgress] = useState(0);

  // View Settings
  const [showTools, setShowTools] = useState(false);
  const [showTranslation, setShowTranslation] = useState(true);
  const [fontSize, setFontSize] = useState(32);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const loadVerses = async () => {
      try {
        const data = await fetchVerses(chapter.id);
        setVerses(data.verses);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadVerses();

    return () => {
      if (audio) {
        audio.pause();
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [chapter.id]);

  // Handle Reading Progress (Scroll)
  useEffect(() => {
    const handleScroll = () => {
      const windowHeight = window.innerHeight;
      const documentHeight = document.documentElement.scrollHeight;
      const scrollTop = window.scrollY;

      // Calculate percentage
      const maxScroll = documentHeight - windowHeight;
      const progress = maxScroll > 0 ? (scrollTop / maxScroll) * 100 : 0;

      setReadingProgress(Math.min(100, Math.max(0, progress)));
    };

    window.addEventListener('scroll', handleScroll);
    // Initial calculation in case we start scrolled or content loads
    handleScroll();

    return () => window.removeEventListener('scroll', handleScroll);
  }, [verses, fontSize, showTranslation]); // Recalculate if layout changes

  const toggleAudio = (verseKey: string) => {
    // If clicking the same verse
    if (playingVerse === verseKey && audio) {
      if (isPlaying) {
        audio.pause();
        setIsPlaying(false);
      } else {
        audio.play();
        setIsPlaying(true);
      }
      return;
    }

    // Stop previous audio
    if (audio) {
      audio.pause();
      setAudioProgress(0);
    }

    // Play new audio
    const url = getAudioUrl(verseKey);
    const newAudio = new Audio(url);

    newAudio.addEventListener('timeupdate', () => {
      if (newAudio.duration) {
        setAudioProgress((newAudio.currentTime / newAudio.duration) * 100);
      }
    });

    newAudio.addEventListener('ended', () => {
      setPlayingVerse(null);
      setIsPlaying(false);
      setAudioProgress(0);
    });

    newAudio.play();
    setAudio(newAudio);
    setPlayingVerse(verseKey);
    setIsPlaying(true);
  };

  const handleShare = async (verse: Verse) => {
    const translationText = verse.translations?.[0]?.text.replace(/<[^>]*>/g, '') || '';
    const shareText = `${verse.text_uthmani}\n\n"${translationText}"\n\n— ${chapter.name_simple} (${verse.verse_key})\n\nRead on Al Quran App`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Al Quran - ${chapter.name_simple} ${verse.verse_key}`,
          text: shareText,
          url: window.location.href
        });
      } catch (err) {
        console.log('Share dismissed');
      }
    } else {
      try {
        await navigator.clipboard.writeText(`${shareText}\n${window.location.href}`);
        alert('Verse copied to clipboard');
      } catch (err) {
        console.error('Failed to copy', err);
      }
    }
  };

  const filteredVerses = verses.filter(verse => {
    const query = searchQuery.toLowerCase();
    const translation = verse.translations?.[0]?.text.toLowerCase() || '';
    const arabic = verse.text_uthmani; 
    const key = verse.verse_key;
    const verseNum = verse.verse_key.split(':')[1];

    return translation.includes(query) || 
           arabic.includes(query) || 
           key.includes(query) ||
           verseNum === query;
  });

  return (
    <div className="min-h-screen bg-[#FDF6F0] pb-24 animate-fade-in relative">
      {/* Header */}
      <div className="sticky top-0 bg-[#FDF6F0]/95 backdrop-blur-md z-30 border-b border-[#EDE0D4]">
        <div className="flex justify-between items-center px-4 py-4">
          <button onClick={onBack} className="p-2 text-stone-600 hover:bg-stone-100 rounded-full transition-colors">
            <ArrowLeft size={24} />
          </button>
          <div className="text-center">
            <h2 className="font-bold text-stone-800 flex items-center gap-2 justify-center">
               <span>{chapter.id}. {chapter.name_simple}</span>
            </h2>
            <p className="text-xs text-stone-400">{chapter.translated_name.name}</p>
          </div>
          <button onClick={() => setShowTools(true)} className="p-2 text-stone-600 hover:bg-stone-100 rounded-full transition-colors">
            <MoreHorizontal size={24} />
          </button>
        </div>

        {/* Global Reading Progress Bar */}
        <div className="w-full h-1 bg-stone-200">
           <div 
             className="h-full bg-[#8B5E3C] transition-all duration-300 ease-out"
             style={{ width: `${readingProgress}%` }}
           />
        </div>
      </div>

      {/* Surah Banner */}
      <div className="px-4 mt-6 mb-6">
        <div className="bg-gradient-to-br from-[#8B5E3C] to-[#6D4C41] rounded-2xl p-6 text-white text-center shadow-lg relative overflow-hidden">
             <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none" 
                  style={{ backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)', backgroundSize: '20px 20px' }}>
             </div>

            <h1 className="font-arabic text-4xl mb-2">{chapter.name_arabic}</h1>
            <p className="text-white/80 text-sm mb-4">{chapter.name_simple} • {chapter.revelation_place}</p>
            <div className="w-full h-px bg-white/20 mb-4 mx-auto max-w-[200px]" />
            <div className="font-arabic text-2xl">بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</div>
        </div>
      </div>

      {/* Search Input within Surah */}
      <div className="px-4 mb-6">
        <div className="relative group">
          <Search className="absolute left-4 top-3.5 text-stone-400 group-focus-within:text-[#8B5E3C] transition-colors" size={18} />
          <input 
            type="text" 
            placeholder={`Search inside ${chapter.name_simple}...`}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-white border border-[#EDE0D4] rounded-xl py-3 pl-11 pr-10 text-stone-700 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-[#8B5E3C]/20 focus:border-[#8B5E3C] transition-all shadow-sm"
          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute right-3 top-3.5 text-stone-400 hover:text-stone-600"
            >
              <X size={18} />
            </button>
          )}
        </div>
      </div>

      {loading ? (
        <Loading />
      ) : (
        <div className="px-4 space-y-6">
          {filteredVerses.length > 0 ? (
            filteredVerses.map((verse) => {
              const isCurrent = playingVerse === verse.verse_key;

              return (
                <div key={verse.id} className={`bg-white rounded-2xl p-5 shadow-sm border transition-all hover:shadow-md relative overflow-hidden ${isCurrent ? 'border-[#8B5E3C] ring-1 ring-[#8B5E3C]/20' : 'border-[#EDE0D4]'}`}>

                  {/* Audio Progress Bar (Only visible when this verse is the current one) */}
                  {isCurrent && (
                    <div className="absolute bottom-0 left-0 h-1.5 bg-[#F5E6DA] w-full z-10">
                       <div 
                         className="h-full bg-[#8B5E3C] transition-all duration-100 ease-linear"
                         style={{ width: `${audioProgress}%` }}
                       />
                    </div>
                  )}

                  {/* Action Bar */}
                  <div className="flex justify-between items-center mb-6 bg-[#FAFAFA] rounded-lg p-2">
                    <span className={`w-8 h-8 flex items-center justify-center text-xs font-bold rounded-full shadow-sm transition-colors ${isCurrent ? 'bg-[#8B5E3C] text-white' : 'bg-[#F5E6DA] text-[#8B5E3C]'}`}>
                      {verse.verse_key.split(':')[1]}
                    </span>
                    <div className="flex space-x-3 text-stone-400">
                      <button 
                        onClick={() => toggleAudio(verse.verse_key)}
                        className={`hover:text-[#8B5E3C] transition-colors ${isCurrent ? 'text-[#8B5E3C]' : ''}`}
                      >
                        {isCurrent && isPlaying ? <Pause size={18} /> : <Play size={18} />}
                      </button>
                      <button className="hover:text-[#8B5E3C] transition-colors"><Bookmark size={18} /></button>
                      <button 
                        onClick={() => handleShare(verse)}
                        className="hover:text-[#8B5E3C] transition-colors"
