import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { Search, Menu } from 'lucide-react';
import { fetchChapters } from './services/quranService';
import { Chapter, NavigationContext } from './types';
import { ChapterRow } from './components/ChapterRow';
import { LastRead } from './components/LastRead';
import { BottomNav } from './components/BottomNav';
import { DetailView } from './components/DetailView';
import { Loading } from './components/Loading';
import { Sidebar } from './components/Sidebar';

// Main Home Component
const Home = ({ onNavigate, onOpenSidebar }: { onNavigate: (ctx: NavigationContext) => void, onOpenSidebar: () => void }) => {
  const [chapters, setChapters] = useState<Chapter[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [listType, setListType] = useState<'surah' | 'hizb'>('surah');

  useEffect(() => {
    const loadChapters = async () => {
      try {
        const data = await fetchChapters();
        setChapters(data.chapters);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadChapters();
  }, []);

  const filteredChapters = chapters.filter(c => 
    c.name_simple.toLowerCase().includes(searchQuery.toLowerCase()) || 
    c.name_arabic.includes(searchQuery) ||
    String(c.id).includes(searchQuery)
  );

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-24">
      <div className="max-w-3xl mx-auto">
        {/* Top Bar */}
        <div className="px-6 py-6 pt-10 flex justify-between items-center bg-[#F8FAFC] sticky top-0 z-10 border-b border-transparent transition-all">
          <div className="flex items-center gap-3">
              <button 
                onClick={onOpenSidebar}
                className="p-2 -ml-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
              >
                  <Menu size={24} />
              </button>
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight flex items-center gap-2">
                Al Quran
                <span className="text-xs bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full">Pro</span>
              </h1>
          </div>
          <div className="w-10 h-10 bg-slate-200 rounded-full overflow-hidden border-2 border-white shadow-sm">
              <img src="https://picsum.photos/200/200" alt="Profile" className="w-full h-full object-cover" />
          </div>
        </div>

        <LastRead />

        {/* Quick Filter Tabs */}
        <div className="px-6 mb-6 overflow-x-auto scrollbar-hide">
          <div className="flex space-x-2 bg-white p-1.5 rounded-xl w-max border border-slate-200 shadow-sm">
              <button 
                  onClick={() => setListType('surah')}
                  className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${listType === 'surah' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                  Surah
              </button>
              <button 
                  onClick={() => setListType('hizb')}
                  className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${listType === 'hizb' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                  Hizb
              </button>
              {['Juz', 'Page'].map((tab) => (
                  <button 
                      key={tab}
                      className={`px-6 py-2 rounded-lg text-sm font-medium transition-all text-slate-400 cursor-not-allowed`}
                  >
                      {tab}
                  </button>
              ))}
          </div>
        </div>

        {/* Search */}
        {listType === 'surah' && (
          <div className="px-6 mb-4">
            <div className="relative group">
                <Search className="absolute left-4 top-3.5 text-slate-400 group-focus-within:text-emerald-600 transition-colors" size={20} />
                <input 
                    type="text"
                    placeholder="Search Surah Name, No..."
                    className="w-full bg-white border border-slate-200 rounded-xl py-3 pl-12 pr-4 text-slate-700 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all shadow-sm"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>
          </div>
        )}

        {/* Content List */}
        <div className="px-6">
          {loading ? (
            <Loading />
          ) : (
            <>
              {listType === 'surah' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {filteredChapters.map(chapter => (
                    <ChapterRow 
                      key={chapter.id} 
                      chapter={chapter} 
                      onClick={() => onNavigate({ type: 'surah', data: chapter })} 
                    />
                  ))}
                </div>
              ) : (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
                  {Array.from({ length: 60 }, (_, i) => i + 1).map(hizbId => (
                    <button
                      key={hizbId}
                      onClick={() => onNavigate({ type: 'hizb', id: hizbId })}
                      className="flex flex-col items-center justify-center p-6 bg-white rounded-xl border border-slate-100 hover:border-emerald-500 hover:shadow-md transition-all group"
                    >
                      <span className="text-emerald-600 font-bold text-lg mb-1 group-hover:scale-110 transition-transform">{hizbId}</span>
                      <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">Hizb</span>
                    </button>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
};

const App = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [navigationContext, setNavigationContext] = useState<NavigationContext | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <HashRouter>
        <div className="w-full bg-slate-50 min-h-screen relative">
            <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            {navigationContext ? (
                <DetailView 
                    context={navigationContext} 
                    onBack={() => setNavigationContext(null)} 
                />
            ) : (
                <>
                    <Home 
                      onNavigate={setNavigationContext} 
                      onOpenSidebar={() => setSidebarOpen(true)}
                    />
                    <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
                </>
            )}
        </div>
    </HashRouter>
  );
};

export default App;

