// Navigation context to handle Surah, Hizb, Juz, and Page views
export type NavigationContext = 
  | { type: 'surah'; data: Chapter }
  | { type: 'hizb'; id: number }
  | { type: 'juz'; id: number }
  | { type: 'page'; id: number };

import { ApiChapterResponse, ApiVerseResponse, ApiTafsirListResponse, TafsirContent } from '../types';

const BASE_URL = 'https://api.quran.com/api/v4';
const CACHE_PREFIX = 'quran_app_v2_';

const getFromCache = <T>(key: string): T | null => {
  try {
    const cachedItem = localStorage.getItem(CACHE_PREFIX + key);
    if (cachedItem) {
      const { data } = JSON.parse(cachedItem);
      return data;
    }
  } catch (error) {
    console.error('Error reading from cache:', error);
  }
  return null;
};

const saveToCache = (key: string, data: any) => {
  try {
    const itemToCache = {
      data,
      timestamp: Date.now(),
    };
    // Basic LRU or cleanup could be added here, but for now we catch quota errors
    localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
  } catch (error) {
    console.warn('Cache quota exceeded, clearing old items...');
    localStorage.clear();
  }
};

export const fetchChapters = async (): Promise<ApiChapterResponse> => {
  const cacheKey = 'chapters_list';
  const cachedData = getFromCache<ApiChapterResponse>(cacheKey);
  if (cachedData) return cachedData;

  try {
    const response = await fetch(`${BASE_URL}/chapters?language=en`);
    if (!response.ok) throw new Error('Failed to fetch chapters');
    const data = await response.json();
    saveToCache(cacheKey, data);
    return data;
  } catch (error) {
    throw error;
  }
};

export const fetchVerses = async (chapterId: number, page: number = 1): Promise<ApiVerseResponse> => {
  const perPage = 20; 
  const cacheKey = `verses_chapter_${chapterId}_page_${page}`;
  const cachedData = getFromCache<ApiVerseResponse>(cacheKey);
  if (cachedData) return cachedData;

  try {
    const response = await fetch(
      `${BASE_URL}/verses/by_chapter/${chapterId}?language=en&words=false&translations=131&fields=text_uthmani&page=${page}&per_page=${perPage}`
    );
    if (!response.ok) throw new Error('Failed to fetch verses');
    const data = await response.json();
