// Navigation context to handle Surah, Hizb, Juz, Page, and Calendar views
export type NavigationContext = 
  | { type: 'surah'; data: Chapter }
  | { type: 'hizb'; id: number }
  | { type: 'juz'; id: number }
  | { type: 'page'; id: number }
  | { type: 'calendar' };

import { HijriDate } from '../types';

export const fetchHijriCalendar = async (month: number, year: number): Promise<HijriDate[]> => {
  try {
    const response = await fetch(`https://api.aladhan.com/v1/gToHCalendar/${month}/${year}`);
    if (!response.ok) throw new Error('Failed to fetch calendar');
    const json = await response.json();
    return json.data;
  } catch (error) {
    console.error('Error fetching Hijri calendar:', error);
    return [];
  }
};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, ChevronLeft, ChevronRight, Calendar as CalendarIcon, Loader2 } from 'lucide-react';
import { HijriDate } from '../types';
import { fetchHijriCalendar } from '../services/hijriService';

interface HijriCalendarProps {
  onBack: () => void;
}

export const HijriCalendar: React.FC<HijriCalendarProps> = ({ onBack }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [calendarData, setCalendarData] = useState<HijriDate[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedDay, setSelectedDay] = useState<HijriDate | null>(null);

  useEffect(() => {
    const loadCalendar = async () => {
      setLoading(true);
      // API expects month 1-12
      const data = await fetchHijriCalendar(currentDate.getMonth() + 1, currentDate.getFullYear());
      setCalendarData(data);
      setLoading(false);

      // Select today if in current view
      const today = new Date();
      const isCurrentMonth = today.getMonth() === currentDate.getMonth() && today.getFullYear() === currentDate.getFullYear();

      if (isCurrentMonth && data.length > 0) {
        const todayData = data.find(d => parseInt(d.gregorian.day) === today.getDate());
        if (todayData) setSelectedDay(todayData);
      } else if (data.length > 0) {
        setSelectedDay(data[0]);
      }
    };
    loadCalendar();
  }, [currentDate]);

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentDate(newDate);
  };

  const weekDays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  // Find Hijri Month Name (from first valid day or middle of month to be safe)
  const hijriMonthName = calendarData.length > 0 ? calendarData[Math.floor(calendarData.length / 2)].hijri.month.en : '';
  const hijriYear = calendarData.length > 0 ? calendarData[Math.floor(calendarData.length / 2)].hijri.year : '';

  // Calculate empty start days
  const startDayIndex = calendarData.length > 0 
    ? weekDays.findIndex(day => day === calendarData[0].gregorian.weekday.en.substr(0, 3)) 
    : 0;

  return (
    <div className="min-h-screen bg-[#F8FAFC] animate-fade-in pb-10">
      {/* Header */}
      <div className="sticky top-0 bg-white/90 backdrop-blur-xl z-30 border-b border-emerald-100 shadow-sm">
        <div className="max-w-3xl mx-auto flex items-center justify-between px-4 py-4">
          <button onClick={onBack} className="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
            <ArrowLeft size={24} />
          </button>
          <div className="text-center">
            <h2 className="font-bold text-slate-800 text-lg">Islamic Calendar</h2>
            <p className="text-xs text-slate-500 font-medium">Hijri {hijriYear}</p>
          </div>
          <div className="w-10"></div> {/* Spacer */}
        </div>
      </div>

      <div className="max-w-3xl mx-auto p-4 sm:p-6">
        {/* Navigation Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-6">
          <div className="flex items-center justify-between mb-6">
             <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
               <ChevronLeft size={24} />
             </button>
             <div className="text-center">
                <h3 className="text-2xl font-bold text-emerald-800 font-arabic">{hijriMonthName}</h3>
                <p className="text-slate-500 font-medium">{monthName}</p>
             </div>
             <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
               <ChevronRight size={24} />
             </button>
          </div>

          {loading ? (
             <div className="flex justify-center items-center h-64">
                <Loader2 className="animate-spin text-emerald-600" size={32} />
             </div>
          ) : (
             <>
                {/* Calendar Grid */}
                <div className="grid grid-cols-7 mb-2">
                  {weekDays.map(day => (
                    <div key={day} className="text-center text-xs font-bold text-slate-400 uppercase tracking-wider py-2">
                      {day}
                    </div>
                  ))}
                </div>
                <div className="grid grid-cols-7 gap-1 sm:gap-2">
                  {/* Empty placeholders */}
                  {Array.from({ length: startDayIndex }).map((_, i) => (
