import { HijriDate } from '../types';

const CACHE_PREFIX = 'hijri_calendar_v1_';

const getFromCache = <T>(key: string): T | null => {
  try {
    const cachedItem = localStorage.getItem(CACHE_PREFIX + key);
    if (cachedItem) {
      const { data } = JSON.parse(cachedItem);
      return data;
    }
  } catch (error) {
    console.error('Error reading from cache:', error);
  }
  return null;
};

const saveToCache = (key: string, data: any) => {
  try {
    const itemToCache = {
      data,
      timestamp: Date.now(),
    };
    localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
  } catch (error) {
    console.warn('Cache quota exceeded for Hijri calendar');
    // Optional: implement LRU or clear specific keys here if needed
  }
};

export const fetchHijriCalendar = async (month: number, year: number): Promise<HijriDate[]> => {
  const cacheKey = `month_${year}_${month}`;

  // 1. Try Cache
  const cachedData = getFromCache<HijriDate[]>(cacheKey);
  if (cachedData) return cachedData;

  // 2. Fetch from API
  try {
    const response = await fetch(`https://api.aladhan.com/v1/gToHCalendar/${month}/${year}`);
    if (!response.ok) throw new Error('Failed to fetch calendar');
    const json = await response.json();

    // 3. Save to Cache
    saveToCache(cacheKey, json.data);
    return json.data;
  } catch (error) {
    console.error('Error fetching Hijri calendar:', error);
    return [];
  }
};

export const prefetchAnnualCalendar = async (year: number) => {
  const promises = [];
  // Prefetch all 12 months for the specified year
  for (let i = 1; i <= 12; i++) {
    const cacheKey = `month_${year}_${i}`;
    if (!getFromCache(cacheKey)) {
      promises.push(fetchHijriCalendar(i, year));
    }
  }

  if (promises.length > 0) {
    await Promise.allSettled(promises);
  }
};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, ChevronLeft, ChevronRight, Calendar as CalendarIcon, Loader2 } from 'lucide-react';
import { HijriDate } from '../types';
import { fetchHijriCalendar, prefetchAnnualCalendar } from '../services/hijriService';

interface HijriCalendarProps {
  onBack: () => void;
}

export const HijriCalendar: React.FC<HijriCalendarProps> = ({ onBack }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [calendarData, setCalendarData] = useState<HijriDate[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedDay, setSelectedDay] = useState<HijriDate | null>(null);

  useEffect(() => {
    const loadCalendar = async () => {
      setLoading(true);
      // API expects month 1-12
      const month = currentDate.getMonth() + 1;
      const year = currentDate.getFullYear();

      const data = await fetchHijriCalendar(month, year);
      setCalendarData(data);
      setLoading(false);

      // Select today if in current view
      const today = new Date();
      const isCurrentMonth = today.getMonth() === currentDate.getMonth() && today.getFullYear() === currentDate.getFullYear();

      if (isCurrentMonth && data.length > 0) {
        const todayData = data.find(d => parseInt(d.gregorian.day) === today.getDate());
        if (todayData) setSelectedDay(todayData);
      } else if (data.length > 0) {
        // Only default to first day if we haven't selected one or if switching months and selection is no longer valid
        // But for simplicity, let's keep selectedDay if it's in the new month, or select first day
        if (!selectedDay || (selectedDay.gregorian.month.number !== month)) {
            setSelectedDay(data[0]);
        }
      }

      // Prefetch current year for offline access
      // We do this after setting data to prioritize the UI
      prefetchAnnualCalendar(year).catch(console.error);
    };
    loadCalendar();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentDate]);

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentDate(newDate);
  };

  const weekDays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  // Find Hijri Month Name (from first valid day or middle of month to be safe)
  const hijriMonthName = calendarData.length > 0 ? calendarData[Math.floor(calendarData.length / 2)].hijri.month.en : '';
  const hijriYear = calendarData.length > 0 ? calendarData[Math.floor(calendarData.length / 2)].hijri.year : '';

  // Calculate empty start days
  const startDayIndex = calendarData.length > 0 
    ? weekDays.findIndex(day => day === calendarData[0].gregorian.weekday.en.substr(0, 3)) 
    : 0;

  return (
    <div className="min-h-screen bg-[#F8FAFC] animate-fade-in pb-10">
      {/* Header */}
      <div className="sticky top-0 bg-white/90 backdrop-blur-xl z-30 border-b border-emerald-100 shadow-sm">
        <div className="max-w-3xl mx-auto flex items-center justify-between px-4 py-4">
          <button onClick={onBack} className="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
            <ArrowLeft size={24} />
          </button>
          <div className="text-center">
            <h2 className="font-bold text-slate-800 text-lg">Islamic Calendar</h2>
            <p className="text-xs text-slate-500 font-medium">Hijri {hijriYear}</p>
          </div>
          <div className="w-10"></div> {/* Spacer */}
        </div>
      </div>

      <div className="max-w-3xl mx-auto p-4 sm:p-6">
        {/* Navigation Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-6">
          <div className="flex items-center justify-between mb-6">
             <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
               <ChevronLeft size={24} />
             </button>
             <div className="text-center">
                <h3 className="text-2xl font-bold text-emerald-800 font-arabic">{hijriMonthName}</h3>
                <p className="text-slate-500 font-medium">{monthName}</p>
             </div>
             <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
               <ChevronRight size={24} />
             </button>
          </div>

          {loading ? (
             <div className="flex justify-center items-center h-64">
                <Loader2 className="animate-spin text-emerald-600" size={32} />
             </div>
          ) : (
             <>
                {/* Calendar Grid */}
                <div className="grid grid-cols-7 mb-2">
                  {weekDays.map(day => (
                    <div key={day} className="text-center text-xs font-bold text-slate-400 uppercase tracking-wider py-2">
                      {day}
                    </div>
                  ))}
                </div>
                <div className="grid grid-cols-7 gap-1 sm:gap-2">
                  {/* Empty placeholders */}
                  {Array.from({ length: startDayIndex }).map((_, i) => (
                    <div key={`empty-${i}`} className="aspect-square" />
                  ))}

                  {/* Days */}
                  {calendarData.map((dayData, i) => {
                    const isToday = 
                      new Date().getDate() === parseInt(dayData.gregorian.day) &&
                      new Date().getMonth() === currentDate.getMonth() &&
                      new Date().getFullYear() === currentDate.getFullYear();

                    const isSelected = selectedDay === dayData;
                    const hasHoliday = dayData.hijri.holidays.length > 0;

                    return (
                      <button
                        key={i}
                        onClick={() => setSelectedDay(dayData)}
                        className={`aspect-square rounded-xl relative flex flex-col items-center justify-center border transition-all duration-200
                          ${isSelected 
                            ? 'bg-emerald-600 text-white border-emerald-600 shadow-lg scale-105 z-10' 
                            : isToday
                              ? 'bg-emerald-50 text-emerald-700 border-emerald-200'
                              : 'bg-white text-slate-700 border-slate-100 hover:border-emerald-200 hover:bg-slate-50'
                          }
                        `}
                      >
                        <span className={`text-sm sm:text-lg font-bold font-arabic mb-1 ${isSelected ? 'text-white' : 'text-slate-800'}`}>
                          {dayData.hijri.day}
                        </span>
                        <span className={`text-[10px] sm:text-xs ${isSelected ? 'text-emerald-100' : 'text-slate-400'}`}>
                          {dayData.gregorian.day}
                        </span>

                        {hasHoliday && (
                          <div className={`absolute bottom-1.5 w-1 h-1 rounded-full ${isSelected ? 'bg-white' : 'bg-red-500'}`} />
                        )}
                      </button>
                    );
                  })}
                </div>
             </>
          )}
        </div>

        {/* Selected Day Details */}
        {selectedDay && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-slide-up">
            <div className="bg-emerald-50/50 p-6 border-b border-emerald-100">
               <div className="flex justify-between items-start">
                  <div>
                    <h4 className="text-emerald-900 font-bold text-lg mb-1">{selectedDay.hijri.weekday.en}</h4>
                    <p className="text-emerald-700">{selectedDay.hijri.day} {selectedDay.hijri.month.en} {selectedDay.hijri.year}</p>
                  </div>
                  <div className="text-right">
                    <h4 className="font-arabic text-2xl text-emerald-800">{selectedDay.hijri.weekday.ar}</h4>
                  </div>
               </div>
            </div>
            <div className="p-6">
                <div className="flex items-center gap-4 mb-4">
                  <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-slate-500">
                     <CalendarIcon size={20} />
                  </div>
                  <div>
                    <p className="text-xs text-slate-400 uppercase font-bold tracking-wider">Gregorian Date</p>
                    <p className="text-slate-800 font-medium">{selectedDay.gregorian.weekday.en}, {selectedDay.gregorian.day} {selectedDay.gregorian.month.en} {selectedDay.gregorian.year}</p>
                  </div>
                </div>

                {selectedDay.hijri.holidays.length > 0 ? (
                  <div className="mt-6">
                    <p className="text-xs text-emerald-600 uppercase font-bold tracking-wider mb-3">Events</p>
                    <div className="space-y-2">
                       {selectedDay.hijri.holidays.map((holiday, idx) => (
                         <div key={idx} className="bg-emerald-50 text-emerald-800 px-4 py-3 rounded-xl text-sm font-medium flex items-center gap-2 border border-emerald-100">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                            {holiday}
                         </div>
                       ))}
                    </div>
                  </div>
                ) : (
                  <p className="text-slate-400 text-sm mt-4 italic">No special Islamic events for this date.</p>
                )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, MoreHorizontal, Play, Pause, Share2, Bookmark, Search, X, Book, ChevronDown, Check } from 'lucide-react';
import { NavigationContext, Verse, TafsirInfo } from '../types';
import { fetchVerses, fetchVersesByHizb, fetchVersesByJuz, fetchVersesByPage, getAudioUrl, fetchTafsirList, fetchTafsirContent } from '../services/quranService';
import { Loading } from './Loading';
import { QuickTools } from './QuickTools';

interface DetailViewProps {
  context: NavigationContext;
  onBack: () => void;
}

export const DetailView: React.FC<DetailViewProps> = ({ context, onBack }) => {
  const [verses, setVerses] = useState<Verse[]>([]);
  const [loading, setLoading] = useState(true);

  // Audio State
  const [playingVerse, setPlayingVerse] = useState<string | null>(null);
  const [audio, setAudio] = useState<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioProgress, setAudioProgress] = useState(0);

  // Reading Progress State
  const [readingProgress, setReadingProgress] = useState(0);

  // View Settings
  const [showTools, setShowTools] = useState(false);
  const [showTranslation, setShowTranslation] = useState(true);
  const [fontSize, setFontSize] = useState(32);
  const [searchQuery, setSearchQuery] = useState('');

  // Tafsir State
  const [selectedTafsirId, setSelectedTafsirId] = useState<number>(169); // Default to Ibn Kathir (English) or similar
  const [tafsirList, setTafsirList] = useState<TafsirInfo[]>([]);
  const [activeTafsirVerse, setActiveTafsirVerse] = useState<Verse | null>(null);
  const [tafsirContent, setTafsirContent] = useState<string>('');
  const [loadingTafsir, setLoadingTafsir] = useState(false);
  const [showTafsirSelector, setShowTafsirSelector] = useState(false);

  // Load Content
  useEffect(() => {
    const loadContent = async () => {
      setLoading(true);
      try {
        let data;
        if (context.type === 'surah') {
          data = await fetchVerses(context.data.id);
        } else if (context.type === 'hizb') {
          data = await fetchVersesByHizb(context.id);
        } else if (context.type === 'juz') {
          data = await fetchVersesByJuz(context.id);
        } else if (context.type === 'page') {
          data = await fetchVersesByPage(context.id);
        }

        if (data) {
          setVerses(data.verses);
        }

        // Pre-load Tafsir list
        const tafsirs = await fetchTafsirList();
        setTafsirList(tafsirs.tafsirs);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadContent();

    return () => {
      if (audio) {
        audio.pause();
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [context]);

  // Handle Reading Progress (Scroll)
  useEffect(() => {
    const handleScroll = () => {
      const windowHeight = window.innerHeight;
      const documentHeight = document.documentElement.scrollHeight;
      const scrollTop = window.scrollY;
      const maxScroll = documentHeight - windowHeight;
      const progress = maxScroll > 0 ? (scrollTop / maxScroll) * 100 : 0;
      setReadingProgress(Math.min(100, Math.max(0, progress)));
    };

    window.addEventListener('scroll', handleScroll);
    handleScroll();
    return () => window.removeEventListener('scroll', handleScroll);
  }, [verses, fontSize, showTranslation]);

  const toggleAudio = (verseKey: string) => {
    if (playingVerse === verseKey && audio) {
      if (isPlaying) {
        audio.pause();
        setIsPlaying(false);
      } else {
        audio.play();
        setIsPlaying(true);
      }
      return;
    }

    if (audio) {
      audio.pause();
      setAudioProgress(0);
    }

    const url = getAudioUrl(verseKey);
    const newAudio = new Audio(url);

    newAudio.addEventListener('timeupdate', () => {
      if (newAudio.duration) {
        setAudioProgress((newAudio.currentTime / newAudio.duration) * 100);
      }
    });

    newAudio.addEventListener('ended', () => {
      setPlayingVerse(null);
      setIsPlaying(false);
      setAudioProgress(0);
    });

    newAudio.play();
    setAudio(newAudio);
    setPlayingVerse(verseKey);
    setIsPlaying(true);
  };

  const openTafsir = async (verse: Verse, tafsirId: number = selectedTafsirId) => {
    setActiveTafsirVerse(verse);
    setLoadingTafsir(true);
    setTafsirContent('');
    try {
      const data = await fetchTafsirContent(tafsirId, verse.verse_key);
      setTafsirContent(data.text);
    } catch (err) {
      console.error(err);
      setTafsirContent('Failed to load Tafsir.');
    } finally {
      setLoadingTafsir(false);
    }
  };

  const handleShare = async (verse: Verse) => {
    const translationText = verse.translations?.[0]?.text.replace(/<[^>]*>/g, '') || '';
    let contextName = '';

    switch(context.type) {
        case 'surah': contextName = context.data.name_simple; break;
        case 'hizb': contextName = `Hizb ${context.id}`; break;
        case 'juz': contextName = `Juz ${context.id}`; break;
        case 'page': contextName = `Page ${context.id}`; break;
    }

    const shareText = `${verse.text_uthmani}\n\n"${translationText}"\n\n— ${contextName} (${verse.verse_key})`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Al Quran - ${verse.verse_key}`,
          text: shareText,
          url: window.location.href
        });
      } catch (err) {
        console.log('Share dismissed');
      }
    } else {
      try {
        await navigator.clipboard.writeText(`${shareText}\n${window.location.href}`);
        alert('Verse copied to clipboard');
      } catch (err) {
        console.error('Failed to copy', err);
      }
    }
  };

  const filteredVerses = verses.filter(verse => {
    const query = searchQuery.toLowerCase();
    const translation = verse.translations?.[0]?.text.toLowerCase() || '';
    const arabic = verse.text_uthmani; 
    const key = verse.verse_key;
    const verseNum = verse.verse_key.split(':')[1];

    return translation.includes(query) || 
           arabic.includes(query) || 
           key.includes(query) ||
           verseNum === query;
  });

  const getHeaderTitle = () => {
    if (context.type === 'surah') return `${context.data.id}. ${context.data.name_simple}`;
    if (context.type === 'hizb') return `Hizb ${context.id}`;
    if (context.type === 'juz') return `Juz ${context.id}`;
    if (context.type === 'page') return `Page ${context.id}`;
    return 'Al Quran';
  };

  const getHeaderSubtitle = () => {
    if (context.type === 'surah') return context.data.translated_name.name;
    return 'Quran Juzu Part';
  };

  // Group Tafsirs by language for the selector
  const groupedTafsirs = tafsirList.reduce((acc, tafsir) => {
    const lang = tafsir.language_name;
    if (!acc[lang]) acc[lang] = [];
    acc[lang].push(tafsir);
    return acc;
  }, {} as Record<string, TafsirInfo[]>);

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-24 animate-fade-in relative">
      {/* Header */}
      <div className="sticky top-0 bg-white/90 backdrop-blur-xl z-30 border-b border-emerald-100 shadow-sm">
        <div className="max-w-3xl mx-auto">
          <div className="flex justify-between items-center px-4 py-4">
            <button onClick={onBack} className="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
              <ArrowLeft size={24} />
            </button>
            <div className="text-center">
              <h2 className="font-bold text-slate-800 flex items-center gap-2 justify-center text-lg">
                <span>{getHeaderTitle()}</span>
              </h2>
              <p className="text-xs text-slate-500 font-medium">{getHeaderSubtitle()}</p>
            </div>
            <button onClick={() => setShowTools(true)} className="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
              <MoreHorizontal size={24} />
            </button>
          </div>
        </div>

        {/* Global Reading Progress Bar */}
        <div className="w-full h-1 bg-slate-100">
           <div 
             className="h-full bg-emerald-600 transition-all duration-300 ease-out shadow-[0_0_10px_rgba(5,150,105,0.4)]"
             style={{ width: `${readingProgress}%` }}
           />
        </div>
      </div>

      <div className="max-w-3xl mx-auto">
        {/* Banner */}
        <div className="px-4 mt-6 mb-6">
          <div className="bg-gradient-to-br from-emerald-800 to-emerald-950 rounded-2xl p-8 text-white text-center shadow-xl shadow-emerald-900/10 relative overflow-hidden ring-1 ring-white/10">
              <div className="absolute top-0 left-0 w-full h-full opacity-5 pointer-events-none" 
                    style={{ backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)', backgroundSize: '24px 24px' }}>
              </div>

              {context.type === 'surah' ? (
                <>
                  <h1 className="font-arabic text-5xl mb-3 drop-shadow-md">{context.data.name_arabic}</h1>
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/10 text-xs font-medium backdrop-blur-sm mb-6 border border-white/10">
                    <span>{context.data.revelation_place}</span>
                    <span className="w-1 h-1 rounded-full bg-white/60"></span>
                    <span>{context.data.verses_count} Verses</span>
                  </div>
                </>
              ) : (
                <h1 className="font-arabic text-4xl mb-6">
                  {context.type === 'hizb' && `Al-Hizb ${context.id}`}
                  {context.type === 'juz' && `Al-Juz ${context.id}`}
                  {context.type === 'page' && `Page ${context.id}`}
                </h1>
              )}

              <div className="w-full h-px bg-gradient-to-r from-transparent via-white/30 to-transparent mb-5 mx-auto max-w-[200px]" />
              <div className="font-arabic text-2xl tracking-wide opacity-90">بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</div>
          </div>
        </div>

        {/* Search Input */}
        <div className="px-4 mb-6">
          <div className="relative group">
            <Search className="absolute left-4 top-3.5 text-slate-400 group-focus-within:text-emerald-600 transition-colors" size={18} />
            <input 
              type="text" 
              placeholder={`Search text...`}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-xl py-3 pl-11 pr-10 text-slate-700 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all shadow-sm"
            />
            {searchQuery && (
              <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-3.5 text-slate-400 hover:text-slate-600"
              >
                <X size={18} />
              </button>
            )}
          </div>
        </div>

        {loading ? (
          <Loading />
        ) : (
          <div className="px-4 space-y-4">
            {filteredVerses.length > 0 ? (
              filteredVerses.map((verse) => {
                const isCurrent = playingVerse === verse.verse_key;

                return (
                  <div key={verse.id} className={`bg-white rounded-2xl p-6 shadow-sm border transition-all duration-300 relative overflow-hidden group
                    ${isCurrent ? 'border-emerald-500 ring-4 ring-emerald-500/5 shadow-lg scale-[1.01]' : 'border-slate-100 hover:border-emerald-100 hover:shadow-md'}`}>

                    {/* Audio Progress Bar */}
                    {isCurrent && (
                      <div className="absolute bottom-0 left-0 h-1 bg-emerald-100 w-full z-10">
                        <div 
                          className="h-full bg-emerald-600 transition-all duration-100 ease-linear"
                          style={{ width: `${audioProgress}%` }}
                        />
                      </div>
                    )}

                    {/* Action Bar */}
                    <div className={`flex justify-between items-start mb-6 rounded-xl p-2 transition-colors ${isCurrent ? 'bg-emerald-50/50' : 'bg-slate-50/50'}`}>
                      <div className={`w-10 h-10 flex items-center justify-center text-sm font-bold rounded-lg shadow-sm transition-colors border ${isCurrent ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white text-emerald-700 border-slate-200'}`}>
                        {verse.verse_key.split(':')[1]}
                      </div>
                      <div className="flex items-center gap-1">
                        <button 
                          onClick={() => toggleAudio(verse.verse_key)}
                          className={`p-2 rounded-full hover:bg-emerald-50 transition-colors ${isCurrent ? 'text-emerald-600' : 'text-slate-400'}`}
                          title="Play"
                        >
                          {isCurrent && isPlaying ? <Pause size={20} /> : <Play size={20} />}
                        </button>
                        <button 
                          onClick={() => openTafsir(verse)}
                          className="p-2 rounded-full hover:bg-emerald-50 text-slate-400 hover:text-emerald-600 transition-colors"
                          title="Read Tafsir"
                        >
                          <Book size={20} />
                        </button>
                        <button className="p-2 rounded-full hover:bg-emerald-50 text-slate-400 hover:text-emerald-600 transition-colors">
                          <Bookmark size={20} />
                        </button>
                        <button 
                          onClick={() => handleShare(verse)}
                          className="p-2 rounded-full hover:bg-emerald-50 text-slate-400 hover:text-emerald-600 transition-colors"
                        >
                          <Share2 size={20} />
                        </button>
                      </div>
                    </div>

                    {/* Arabic Text */}
                    <p 
                      className="text-right font-arabic text-slate-800 leading-[2.6] mb-8"
                      style={{ fontSize: `${fontSize}px` }}
                    >
                      {verse.text_uthmani}
                    </p>

                    {/* Translation */}
                    {showTranslation && (
                      <div className="text-slate-600 text-base md:text-lg leading-relaxed border-t border-slate-100 pt-6">
                        <p className="text-[10px] text-emerald-600 uppercase tracking-wider font-bold mb-2 flex items-center gap-1">
                          Sahih International
                        </p>
                        {verse.translations?.[0]?.text.replace(/<[^>]*>/g, '')}
                      </div>
                    )}
                  </div>
                );
              })
            ) : (
              <div className="text-center py-20">
                <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-slate-50 text-slate-300 mb-6">
                  <Search size={40} />
                </div>
                <p className="text-slate-600 font-semibold text-lg">No verses found</p>
                <p className="text-sm text-slate-400 mt-2">Try adjusting your search query.</p>
              </div>
            )}

            {filteredVerses.length > 0 && (
              <div className="text-center py-10">
                  <div className="w-16 h-1 bg-slate-200 mx-auto rounded-full mb-3"></div>
                  <p className="text-slate-400 text-sm font-medium">End of Section</p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Tafsir Modal/Drawer */}
      {activeTafsirVerse && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity" onClick={() => setActiveTafsirVerse(null)} />
          <div className="bg-white w-full sm:max-w-xl h-[85vh] sm:h-[80vh] rounded-t-3xl sm:rounded-3xl shadow-2xl z-10 flex flex-col animate-slide-up relative">
            {/* Modal Header */}
            <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-white rounded-t-3xl">
              <div>
                 <h3 className="font-bold text-slate-800 text-lg">Tafsir</h3>
                 <button 
                  onClick={() => setShowTafsirSelector(!showTafsirSelector)}
                  className="text-xs text-emerald-600 font-medium flex items-center gap-1 mt-0.5 hover:underline"
                 >
                   {tafsirList.find(t => t.id === selectedTafsirId)?.name || 'Select Tafsir'}
                   <ChevronDown size={14} />
                 </button>
              </div>
              <button onClick={() => setActiveTafsirVerse(null)} className="p-2 bg-slate-100 rounded-full text-slate-500 hover:bg-slate-200">
                <X size={20} />
              </button>
            </div>

            {/* Tafsir Selector Dropdown (Absolute overlay) */}
            {showTafsirSelector && (
              <div className="absolute top-[70px] left-0 right-0 bottom-0 bg-white z-20 overflow-y-auto p-4 animate-fade-in">
                 {Object.keys(groupedTafsirs).sort().map(lang => (
                   <div key={lang} className="mb-6">
                     <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 px-2">{lang}</h4>
                     <div className="grid grid-cols-1 gap-1">
                       {groupedTafsirs[lang].map(tafsir => (
                         <button
                           key={tafsir.id}
                           onClick={() => {
                             setSelectedTafsirId(tafsir.id);
                             setShowTafsirSelector(false);
                             // Reload tafsir content
                             if(activeTafsirVerse) openTafsir(activeTafsirVerse, tafsir.id);
                           }}
                           className={`flex items-center justify-between px-3 py-3 rounded-lg text-left text-sm ${selectedTafsirId === tafsir.id ? 'bg-emerald-50 text-emerald-700 font-medium' : 'text-slate-600 hover:bg-slate-50'}`}
                         >
                           <span>{tafsir.name} <span className="text-slate-400 text-xs ml-1">- {tafsir.author_name}</span></span>
                           {selectedTafsirId === tafsir.id && <Check size={16} />}
                         </button>
                       ))}
                     </div>
                   </div>
                 ))}
              </div>
            )}

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-6">
              <div className="mb-6 bg-slate-50 p-4 rounded-xl border border-slate-100">
                <p className="font-arabic text-xl text-right leading-loose text-slate-800">{activeTafsirVerse.text_uthmani}</p>
              </div>

              {loadingTafsir ? (
                <div className="flex justify-center py-10"><Loading /></div>
              ) : (
                <div className="prose prose-emerald prose-sm max-w-none text-slate-600 leading-7">
                   <div dangerouslySetInnerHTML={{ __html: tafsirContent }} />
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      <QuickTools 
        isOpen={showTools} 
        onClose={() => setShowTools(false)} 
        showTranslation={showTranslation}
        toggleTranslation={() => setShowTranslation(!showTranslation)}
        fontSize={fontSize}
        setFontSize={setFontSize}
      />
    </div>
  );
};

export interface Chapter {
  id: number;
  revelation_place: string;
  revelation_order: number;
  bismillah_pre: boolean;
  name_simple: string;
  name_complex: string;
  name_arabic: string;
  verses_count: number;
  translated_name: {
    language_name: string;
    name: string;
  };
}

export interface Verse {
  id: number;
  verse_key: string;
  text_uthmani: string;
  text_imlaei?: string;
  translations?: Translation[];
  audio?: {
    url: string;
  };
}

export interface Translation {
  id: number;
  resource_id: number;
  text: string;
}

export interface TranslationResource {
  id: number;
  name: string;
  author_name: string;
  slug: string;
  language_name: string;
  translated_name: {
    name: string;
    language_name: string;
  };
}

export interface TafsirInfo {
  id: number;
  name: string;
  author_name: string;
  slug: string;
  language_name: string;
  translated_name: {
    name: string;
    language_name: string;
  };
}

export interface TafsirContent {
  resource_id: number;
  text: string;
}

export interface HijriDate {
  gregorian: {
    date: string;
    day: string;
    weekday: { en: string };
    month: { number: number; en: string };
    year: string;
  };
  hijri: {
    date: string;
    day: string;
    weekday: { en: string; ar: string };
    month: { number: number; en: string; ar: string };
    year: string;
    holidays: string[];
  };
}

export interface ApiChapterResponse {
  chapters: Chapter[];
}

export interface ApiVerseResponse {
  verses: Verse[];
  pagination: {
    per_page: number;
    current_page: number;
    next_page: number | null;
    total_pages: number;
    total_records: number;
  };
}

export interface ApiTafsirListResponse {
  tafsirs: TafsirInfo[];
}

export interface ApiTranslationResourceResponse {
  translations: TranslationResource[];
}

// Navigation context to handle Surah, Hizb, Juz, Page, and Calendar views
export type NavigationContext = 
  | { type: 'surah'; data: Chapter }
  | { type: 'hizb'; id: number }
  | { type: 'juz'; id: number }
  | { type: 'page'; id: number }
  | { type: 'calendar' };

import { ApiChapterResponse, ApiVerseResponse, ApiTafsirListResponse, TafsirContent, ApiTranslationResourceResponse } from '../types';

const BASE_URL = 'https://api.quran.com/api/v4';
const CACHE_PREFIX = 'quran_app_v2_';

const getFromCache = <T>(key: string): T | null => {
  try {
    const cachedItem = localStorage.getItem(CACHE_PREFIX + key);
    if (cachedItem) {
      const { data } = JSON.parse(cachedItem);
      return data;
    }
  } catch (error) {
    console.error('Error reading from cache:', error);
  }
  return null;
};

const saveToCache = (key: string, data: any) => {
  try {
    const itemToCache = {
      data,
      timestamp: Date.now(),
    };
    // Basic LRU or cleanup could be added here, but for now we catch quota errors
    localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
  } catch (error) {
    console.warn('Cache quota exceeded, clearing old items...');
    try {
        localStorage.clear();
        localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
    } catch (e) {
        console.error("Critical storage error", e);
    }
  }
};

export const fetchChapters = async (): Promise<ApiChapterResponse> => {
  const cacheKey = 'chapters_list';
  const cachedData = getFromCache<ApiChapterResponse>(cacheKey);
  if (cachedData) return cachedData;

  try {
    const response = await fetch(`${BASE_URL}/chapters?language=en`);
    if (!response.ok) throw new Error('Failed to fetch chapters');
    const data = await response.json();
    saveToCache(cacheKey, data);
    return data;
