const App = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [navigationContext, setNavigationContext] = useState<NavigationContext | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Translation State
  // Default to 131 (Sahih International - English)
  const [selectedTranslationId, setSelectedTranslationId] = useState(() => {
    const saved = localStorage.getItem('selectedTranslationId');
    return saved ? parseInt(saved, 10) : 131;
  });
  const [selectedTranslationName, setSelectedTranslationName] = useState(() => {
    return localStorage.getItem('selectedTranslationName') || 'Sahih International';
  });
  const [languageModalOpen, setLanguageModalOpen] = useState(false);

  const handleTranslationSelect = (id: number, name: string) => {
    setSelectedTranslationId(id);
    setSelectedTranslationName(name);
    localStorage.setItem('selectedTranslationId', id.toString());
    localStorage.setItem('selectedTranslationName', name);
  };

  // Helper to render content based on navigation
  const renderContent = () => {
    if (navigationContext?.type === 'calendar') {
      return <HijriCalendar onBack={() => setNavigationContext(null)} />;
    }

    if (navigationContext) {
      return (
        <DetailView 
          context={navigationContext} 
          onBack={() => setNavigationContext(null)} 
          translationId={selectedTranslationId}
          translationName={selectedTranslationName}
        />
      );
    }

    return (
      <>
        <Home 
          onNavigate={setNavigationContext} 
          onOpenSidebar={() => setSidebarOpen(true)}
        />
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      </>
    );
  };

  return (
    <HashRouter>
        <div className="w-full bg-slate-50 min-h-screen relative">
            <Sidebar 
              isOpen={sidebarOpen} 
              onClose={() => setSidebarOpen(false)} 
              onNavigate={setNavigationContext}
              onOpenLanguage={() => setLanguageModalOpen(true)}
            />

            <LanguageSelector 
              isOpen={languageModalOpen}
              onClose={() => setLanguageModalOpen(false)}
              selectedId={selectedTranslationId}
              onSelect={handleTranslationSelect}
            />

            {renderContent()}
        </div>
    </HashRouter>
  );
};

export default App;

import { ApiChapterResponse, ApiVerseResponse, ApiTafsirListResponse, TafsirContent, ApiTranslationResourceResponse } from '../types';

const BASE_URL = 'https://api.quran.com/api/v4';
const CACHE_PREFIX = 'quran_app_v2_';

const getFromCache = <T>(key: string): T | null => {
  try {
    const cachedItem = localStorage.getItem(CACHE_PREFIX + key);
    if (cachedItem) {
      const { data } = JSON.parse(cachedItem);
      return data;
    }
  } catch (error) {
    console.error('Error reading from cache:', error);
  }
  return null;
};

const saveToCache = (key: string, data: any) => {
  const itemToCache = {
    data,
    timestamp: Date.now(),
  };
  try {
    // Basic LRU or cleanup could be added here, but for now we catch quota errors
    localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
  } catch (error) {
    console.warn('Cache quota exceeded, clearing old items...');
    try {
        localStorage.clear();
        localStorage.setItem(CACHE_PREFIX + key, JSON.stringify(itemToCache));
    } catch (e) {
        console.error("Critical storage error", e);
    }
  }
};

export const fetchChapters = async (): Promise<ApiChapterResponse> => {
  const cacheKey = 'chapters_list';
  const cachedData = getFromCache<ApiChapterResponse>(cacheKey);
  if (cachedData) return cachedData;

  try {
    const response = await fetch(`${BASE_URL}/chapters?language=en`);
    if (!response.ok) throw new Error('Failed to fetch chapters');
    const data = await response.json();
    saveToCache(cacheKey, data);
    return data;
  } catch (error) {
    throw error;
  }
};

export const fetchVerses = async (chapterId: number, page: number = 1, translationId: number = 131): Promise<ApiVerseResponse> => {
  const perPage = 20; 
  // Include translationId in cache key
  const cacheKey = `verses_chapter_${chapterId}_page_${page}_tr_${translationId}`;
  const cachedData = getFromCache<ApiVerseResponse>(cacheKey);
  if (cachedData) return cachedData;

  try {
    const response = await fetch(
      `${BASE_URL}/verses/by_chapter/${chapterId}?language=en&words=false&translations=${translationId}&fields=text_uthmani&page=${page}&per_page=${perPage}`
    );
    if (!response.ok) throw new Error('Failed to fetch verses');
    const data = await response.json();
    saveToCache(cacheKey, data);
    return data;
  } catch (error) {
    throw error;
  }
};

